// Unpack Notion property objects.
// ── Adjust property key strings to match your actual Creators DB column names ──
const p = $input.first().json.properties ?? {};

const text   = prop => prop?.rich_text?.[0]?.plain_text ?? prop?.title?.[0]?.plain_text ?? '';
const sel    = prop => prop?.select?.name ?? '';
const em     = prop => prop?.email ?? '';
const multi  = prop => (prop?.multi_select ?? []).map(s => s.name);
const dt     = prop => prop?.date?.start ?? '';

const c = {
  page_id:                $input.first().json.id,
  page_url:               $input.first().json.url,
  brand_name:             text(p['Name'] ?? p['Brand']),
  contact_name:           text(p['Contact Name']),
  contact_email:          em(p['Contact Email']),
  team_structure:         sel(p['Team Structure']),
  platforms_active:       multi(p['Platforms']),
  primary_format:         sel(p['Primary Format']),
  publishing_frequency:   sel(p['Publishing Frequency']),
  repurposing_today:      sel(p['Repurposing']),
  tools_editing:          text(p['Tools — Editing']),
  tools_scheduling:       text(p['Tools — Scheduling']),
  tools_storage:          text(p['Tools — Storage']),
  tools_analytics:        text(p['Tools — Analytics']),
  tools_calendar:         sel(p['Content Calendar Tool']),
  monetization_channels:  multi(p['Monetization']),
  monetization_goal:      text(p['Monetization Goal']),
  bottleneck_primary:     sel(p['Bottleneck']),
  bottleneck_description: text(p['Bottleneck Description']),
  outcome_30d:            text(p['Outcome 30d']),
  brand_tone:             sel(p['Brand Tone']),
  content_topics:         text(p['Content Topics']),
  content_prohibited:     text(p['Prohibited']),
  brand_deal_restrictions:text(p['Brand Deal Restrictions']),
  approval_workflow:      sel(p['Approval Workflow']),
  platforms_restricted:   text(p['Restricted Platforms']),
  submitted_at:           dt(p['Submitted At']),
};

return [{ json: c }];

const c = $input.first().json;

const toolsStr = [
  c.tools_editing    && `Editing: ${c.tools_editing}`,
  c.tools_scheduling && `Scheduling: ${c.tools_scheduling}`,
  c.tools_storage    && `Storage: ${c.tools_storage}`,
  c.tools_analytics  && `Analytics: ${c.tools_analytics}`,
  c.tools_calendar   && `Content calendar: ${c.tools_calendar}`,
].filter(Boolean).join('\n');

const platformsStr  = (c.platforms_active || []).join(', ');
const monetStr      = (c.monetization_channels || []).join(', ');

// Brand slug for environment/project naming
const slug = (c.brand_name || 'creator').toLowerCase().replace(/[^a-z0-9]/g, '-').replace(/-+/g, '-').replace(/^-|-$/g, '').slice(0, 24);

const prompt = `You are an expert creator operations architect. Based on this creator intake, generate a content systems blueprint as structured JSON. Be specific — this drives a real pipeline build, not a generic plan.

CREATOR INTAKE DATA:
Brand: ${c.brand_name}
Team: ${c.team_structure}
Platforms active: ${platformsStr}
Primary format: ${c.primary_format}
Publishing frequency: ${c.publishing_frequency}
Repurposing today: ${c.repurposing_today}
Monetization: ${monetStr}
Monetization goal (90d): ${c.monetization_goal || 'not specified'}
Primary bottleneck: ${c.bottleneck_primary}
Bottleneck detail: ${c.bottleneck_description}
Desired 30-day outcome: ${c.outcome_30d}
Brand tone: ${c.brand_tone}
Content topics: ${c.content_topics || 'not specified'}
Prohibited topics: ${c.content_prohibited || 'none stated'}
Brand deal restrictions: ${c.brand_deal_restrictions || 'none'}
Approval workflow: ${c.approval_workflow}
Restricted platforms (no auto-post): ${c.platforms_restricted || 'none'}

Tools:\n${toolsStr || 'not specified'}

Return ONLY a raw JSON object (no markdown fences, no explanation). Use this exact schema:
{
  "platform_maturity": "Starting Out | Active | Scaling",
  "primary_focus": ["one or more of: Short-form Video, Long-form Video, Newsletter, Podcasting, Social Growth, Monetization, Repurposing"],
  "brand_safety_level": "Open | Brand Deal Safe | Restricted",
  "brand_snapshot": [
    "Primary platform and audience size/stage bullet",
    "Content format mix and publishing cadence bullet",
    "Monetization stage and primary revenue channel bullet"
  ],
  "bottlenecks": [
    { "text": "specific bottleneck description", "category": "Publishing | Repurposing | Analytics | Monetization | Asset Ops" },
    { "text": "...", "category": "..." },
    { "text": "...", "category": "..." }
  ],
  "platform_health_notes": "1-2 sentences on gaps — underserved platforms, inconsistent cadence, missed repurposing opportunities",
  "outcomes_30d": ["specific, measurable outcome 1", "outcome 2", "outcome 3"],
  "outcomes_90d": ["specific, measurable outcome 1", "outcome 2", "outcome 3"],
  "constraints": ["content or platform constraint from brand deals, approval workflow, or platform policy"],
  "platform_strategy": {
    "primary": "single platform to focus on first",
    "secondary": ["platform to repurpose to", "..."],
    "experimental": ["new platform to test"],
    "reason": "one sentence on why this priority order"
  },
  "content_stack": [
    { "layer": "Calendar", "tool": "recommended tool", "purpose": "one-line purpose", "notes": "any setup or safety note" },
    { "layer": "Editing", "tool": "recommended tool", "purpose": "one-line purpose", "notes": "note" },
    { "layer": "Scheduling", "tool": "recommended tool", "purpose": "one-line purpose", "notes": "note" },
    { "layer": "Storage", "tool": "recommended tool", "purpose": "one-line purpose", "notes": "note" },
    { "layer": "Analytics", "tool": "recommended tool", "purpose": "one-line purpose", "notes": "note" }
  ],
  "pipelines": [
    {
      "number": "4.1",
      "category": "Publishing | Repurposing | Analytics | Monetization | Asset Ops",
      "name": "Short name (3-5 words)",
      "goal": "one sentence",
      "trigger": "what event or schedule fires this pipeline",
      "platforms": ["platform names involved"],
      "tools": ["tool names"],
      "mcp_tools": ["specific MCP tool names e.g. social_post_all, n8n_run_workflow"],
      "safety_notes": "what the agent must NOT do autonomously — what requires human approval",
      "effort": "Low | Medium | High"
    },
    { "number": "4.2", "category": "Repurposing", "name": "...", "goal": "...", "trigger": "...", "platforms": ["..."], "tools": ["..."], "mcp_tools": ["..."], "safety_notes": "...", "effort": "Medium" },
    { "number": "4.3", "category": "Analytics", "name": "...", "goal": "...", "trigger": "...", "platforms": ["..."], "tools": ["..."], "mcp_tools": ["..."], "safety_notes": "...", "effort": "Low" }
  ],
  "brand_voice": {
    "tone": "brief description of voice and style",
    "topics": ["core topic 1", "core topic 2", "core topic 3"],
    "prohibited": ["topic or content type to never post"],
    "approval_required": "always | scheduled-content-ok | never",
    "notes": "any brand deal or exclusivity constraint the agent must enforce"
  },
  "platform_rules": [
    { "platform": "platform name", "best_times": "posting time recommendation", "hashtag_strategy": "brief", "format_notes": "aspect ratio, length, etc.", "restrictions": "any content policy constraint" }
  ],
  "agent_guardrails": [
    "Agent must never publish to [restricted platform] without human confirmation",
    "Agent must never post content mentioning [prohibited topics]",
    "Agent must never approve brand deal content — route to human for final sign-off",
    "Agent must always apply SOCIAL_ALLOWED_PLATFORMS allow-list before any post action",
    "Agent must never modify, delete, or repost published content without explicit instruction"
  ]
}`;

return [{ json: { prompt, creator: c } }];

// ── Parse Claude response ────────────────────────────────────────────
let b;
try {
  const raw = $input.first().json.content[0].text.trim();
  const clean = raw.startsWith('```') ? raw.replace(/^```[a-z]*\n?/, '').replace(/\n?```$/, '') : raw;
  b = JSON.parse(clean);
} catch (e) {
  b = {
    platform_maturity: 'Active', primary_focus: ['Other'], brand_safety_level: 'Open',
    brand_snapshot: ['Brand snapshot pending review.', '', ''],
    bottlenecks: [{ text: 'Bottleneck details — see linked Creator page.', category: 'Publishing' }],
    platform_health_notes: 'Platform health to be confirmed during onboarding call.',
    outcomes_30d: ['30-day outcomes to be confirmed.', '', ''],
    outcomes_90d: ['90-day outcomes to be confirmed.', '', ''],
    constraints: ['Constraints to be confirmed.'],
    platform_strategy: { primary: 'TBD', secondary: [], experimental: [], reason: 'TBD' },
    content_stack: [
      { layer: 'Calendar', tool: 'Notion', purpose: 'Content planning', notes: 'TBD' },
      { layer: 'Editing', tool: 'TBD', purpose: 'TBD', notes: '' },
      { layer: 'Scheduling', tool: 'TBD', purpose: 'TBD', notes: '' },
      { layer: 'Storage', tool: 'TBD', purpose: 'TBD', notes: '' },
      { layer: 'Analytics', tool: 'TBD', purpose: 'TBD', notes: '' },
    ],
    pipelines: [
      { number: '4.1', category: 'Publishing', name: 'Pipeline 1 TBD', goal: 'TBD', trigger: 'TBD', platforms: ['TBD'], tools: ['TBD'], mcp_tools: ['TBD'], safety_notes: 'TBD', effort: 'Medium' },
      { number: '4.2', category: 'Repurposing', name: 'Pipeline 2 TBD', goal: 'TBD', trigger: 'TBD', platforms: ['TBD'], tools: ['TBD'], mcp_tools: ['TBD'], safety_notes: 'TBD', effort: 'Medium' },
      { number: '4.3', category: 'Analytics', name: 'Pipeline 3 TBD', goal: 'TBD', trigger: 'TBD', platforms: ['TBD'], tools: ['TBD'], mcp_tools: ['TBD'], safety_notes: 'TBD', effort: 'Low' },
    ],
    brand_voice: { tone: 'TBD', topics: ['TBD'], prohibited: ['TBD'], approval_required: 'always', notes: 'TBD' },
    platform_rules: [],
    agent_guardrails: [
      'Agent must never post to restricted platforms without human confirmation.',
      'Agent must always apply SOCIAL_ALLOWED_PLATFORMS allow-list.',
      'Agent must never approve brand deal content — route to human.',
    ],
  };
}

const c = $('Extract Creator Fields').item.json;

// ── Block helpers (Notion API format) ─────────────────────────────────
const rt    = t => [{ type: 'text', text: { content: String(t || ' ') } }];
const h1    = t => ({ object: 'block', type: 'heading_1',          heading_1:          { rich_text: rt(t) } });
const h3    = t => ({ object: 'block', type: 'heading_3',          heading_3:          { rich_text: rt(t) } });
const para  = t => ({ object: 'block', type: 'paragraph',          paragraph:          { rich_text: rt(t) } });
const bul   = t => ({ object: 'block', type: 'bulleted_list_item', bulleted_list_item: { rich_text: rt(t) } });
const todo  = (t, chk = false) => ({ object: 'block', type: 'to_do', to_do: { rich_text: rt(t), checked: chk } });
const call  = (t, emoji = 'ℹ️') => ({ object: 'block', type: 'callout', callout: { rich_text: rt(t), icon: { type: 'emoji', emoji } } });
const div   = () => ({ object: 'block', type: 'divider', divider: {} });

// Brand safety level map
const safetyMap = {
  'Open': 'Open',
  'Brand Deal Safe': 'Brand Deal Safe',
  'Restricted': 'Restricted',
};
const safetyLevel = b.brand_safety_level || 'Open';

// Tool list from intake
const toolLines = [
  c.tools_editing    && `Editing: ${c.tools_editing}`,
  c.tools_scheduling && `Scheduling: ${c.tools_scheduling}`,
  c.tools_storage    && `Storage: ${c.tools_storage}`,
  c.tools_analytics  && `Analytics: ${c.tools_analytics}`,
  c.tools_calendar   && `Content calendar: ${c.tools_calendar}`,
].filter(Boolean);

const platformStr = (c.platforms_active || []).join(', ');
const monetStr    = (c.monetization_channels || []).join(', ');

// ── SECTION 1 + 2: Content Snapshot + Goals ───────────────────────────
const s12 = [
  call('Auto-generated from creator intake. Review before sharing with creator.', '🤖'),
  div(),
  h1('1. Current State (Content Snapshot)'),
  h3('Brand Profile'),
  ...b.brand_snapshot.filter(Boolean).map(bul),
  bul(`Approval workflow: ${c.approval_workflow || 'not specified'}`),
  h3('Platforms Active'),
  bul(platformStr || 'No platforms specified.'),
  bul(`Publishing frequency: ${c.publishing_frequency || 'not specified'}`),
  bul(`Repurposing today: ${c.repurposing_today || 'not specified'}`),
  h3('Current Tools'),
  ...(toolLines.length ? toolLines.map(bul) : [para('No tools specified in intake.')]),
  h3('Monetization'),
  bul(monetStr || 'No monetization channels specified.'),
  bul(`Monetization goal (90d): ${c.monetization_goal || 'not specified'}`),
  h3('Content Operations Bottlenecks'),
  ...b.bottlenecks.map(bt => bul(`[${bt.category}] ${bt.text}`)),
  h3('Platform Health'),
  para(b.platform_health_notes),
  div(),
  h1('2. Content Goals (30–90 Days)'),
  h3('30-Day Outcomes'),
  ...b.outcomes_30d.filter(Boolean).map(bul),
  h3('90-Day Outcomes'),
  ...b.outcomes_90d.filter(Boolean).map(bul),
  h3('Constraints / Non-Negotiables'),
  ...(b.constraints.length ? b.constraints.map(bul) : [para('No constraints stated.')]),
  ...(c.brand_deal_restrictions ? [bul(`Brand deal restrictions: ${c.brand_deal_restrictions}`)] : []),
  ...(c.platforms_restricted ? [bul(`Restricted platforms (no auto-post): ${c.platforms_restricted}`)] : []),
  div(),
];

// ── SECTION 3: Content Stack ──────────────────────────────────────────
const strat = b.platform_strategy || {};
const s3 = [
  h1('3. Recommended Content Stack'),
  h3('3.1 Platform Strategy'),
  bul(`Primary (build depth here first): ${strat.primary || 'TBD'}`),
  bul(`Secondary (repurpose to): ${(strat.secondary || []).join(', ') || 'TBD'}`),
  bul(`Experimental (test & measure): ${(strat.experimental || []).join(', ') || 'none'}`),
  bul(`Rationale: ${strat.reason || 'TBD'}`),
  h3('3.2 Content Stack by Layer'),
  para('[shared] = DiscoAgents managed   [creator] = creator-owned account / subscription'),
  ...(b.content_stack || []).map(row =>
    bul(`[creator] ${row.layer}: ${row.tool} — ${row.purpose}${row.notes ? ' · ' + row.notes : ''}`)
  ),
  h3('3.3 Content Calendar Structure'),
  bul(`Calendar tool: ${c.tools_calendar || strat.calendar_tool || 'Notion (recommended)'}`),
  bul('Columns: Title, Format, Platform(s), Publish Date, Status (Idea / Scripted / Filmed / Edited / Scheduled / Live), Asset Link'),
  bul('One row per piece of content. Repurposed versions linked as sub-items.'),
  div(),
];

// ── SECTION 4: Priority Pipelines ────────────────────────────────────
const s4 = [h1('4. Priority Content Pipelines (v1)')];
for (const p of (b.pipelines || []).slice(0, 3)) {
  s4.push(
    h3(`${p.number} [${p.category}] – ${p.name}  ·  Effort: ${p.effort}`),
    bul(`Goal: ${p.goal}`),
    bul(`Trigger: ${p.trigger}`),
    bul(`Platforms: ${(p.platforms || []).join(', ')}`),
    bul(`Tools: ${(p.tools || []).join(', ')}`),
    bul(`MCP tools: ${(p.mcp_tools || []).join(', ')}`),
    bul(`Safety: ${p.safety_notes}`),
  );
}
s4.push(
  div(),
  call('v1 limit: 3 pipelines buildable in 30 days. Validate performance before adding v2 automations.', '⚠️'),
  div(),
);

// ── SECTION 5 + 6: Brand Voice + Launch Plan ──────────────────────────
const bv = b.brand_voice || {};
const pipelineName = i => (b.pipelines && b.pipelines[i]) ? b.pipelines[i].name : `Pipeline ${i + 1} TBD`;

const s56 = [
  h1('5. Brand Voice & Platform Rules'),
  h3('Brand Voice'),
  bul(`Tone: ${bv.tone || c.brand_tone || 'not specified'}`),
  bul(`Core topics: ${(bv.topics || []).join(', ') || c.content_topics || 'not specified'}`),
  bul(`Prohibited: ${(bv.prohibited || []).join(', ') || c.content_prohibited || 'none stated'}`),
  bul(`Approval required: ${bv.approval_required || c.approval_workflow || 'always'}`),
  ...(bv.notes ? [bul(`Notes: ${bv.notes}`)] : []),
  h3('Platform-Specific Rules'),
  ...((b.platform_rules || []).length
    ? b.platform_rules.map(r =>
        bul(`${r.platform}: post at ${r.best_times} · hashtags: ${r.hashtag_strategy} · format: ${r.format_notes}${r.restrictions ? ' · restriction: ' + r.restrictions : ''}`)
      )
    : [para('Platform rules to be filled in after intake review.')]
  ),
  h3('Agent Guardrails'),
  call('These rules are hard constraints — the agent must enforce them on every run.', '🔒'),
  ...(b.agent_guardrails || []).map(g => bul(g)),
  bul('Agent must always check SOCIAL_ALLOWED_PLATFORMS allow-list before any publish action.'),
  bul('Agent must always check SOCIAL_MAX_POST_LENGTH before submitting any caption or post body.'),
  bul('Agent must log all publish actions to MCP audit trail (.logs/mcp-audit.log).'),
  div(),
  h1('6. 30-Day Content Pipeline Launch Plan'),
  h3('Week 1 – Foundation'),
  todo('Connect platform accounts: verify OAuth tokens for all active platforms in SOCIAL_ALLOWED_PLATFORMS'),
  todo('Import content calendar template into ' + (c.tools_calendar || 'Notion') + ' and populate with 30 days of planned content'),
  todo('Set up asset storage: naming convention, folder structure, shared access for team'),
  todo('Configure SOCIAL_ALLOWED_PLATFORMS, SOCIAL_MAX_POST_LENGTH env vars and test allow-list enforcement'),
  todo('Set up Discord alert channel for all pipeline run notifications and errors'),
  h3('Week 2 – Wire Core Pipelines'),
  todo(`Build Pipeline 4.1: ${pipelineName(0)} — full end-to-end with human approval gate and Discord status alert`),
  todo(`Build Pipeline 4.2: ${pipelineName(1)} — full end-to-end`),
  todo('Test approval workflow: confirm all restricted-platform posts require manual confirmation before publish'),
  todo('Validate brand safety: run test posts through prohibited-topic filter'),
  todo('Spot-check MCP audit log after first live pipeline runs'),
  h3('Week 3–4 – Hardening & Handoff'),
  todo(`Build Pipeline 4.3: ${pipelineName(2)} — full end-to-end`),
  todo('Performance review: pull first analytics data, validate against 30-day outcome targets'),
  todo('Tune publishing schedule and repurposing rules based on early data'),
  todo('Write creator runbook: how to add new content, pause a pipeline, and escalate issues'),
  todo('Final sign-off: creator confirms live pipelines are hitting consistency and quality bar'),
  div(),
  call(`Auto-generated from creator intake (${c.submitted_at ? c.submitted_at.slice(0, 10) : 'date unknown'}). Generated: ${new Date().toISOString().slice(0, 10)}.`, '📋'),
];

return [{
  json: {
    s12:              JSON.stringify({ children: s12 }),
    s3:               JSON.stringify({ children: s3 }),
    s4:               JSON.stringify({ children: s4 }),
    s56:              JSON.stringify({ children: s56 }),
    blueprint_title:  `${c.brand_name} – Content Pipeline Blueprint v1`,
    platform_maturity: b.platform_maturity,
    primary_focus:    b.primary_focus,
    brand_safety_level: safetyLevel,
    creator_page_id:  c.page_id,
    creator:          c,
  }
}];
